"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[464],{638:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new `StatController`. Numeric leaf values in `data` are flattened\\ninto dot-separated stat keys.\\n\\n```lua\\n-- Nested table \u2192 flat keys\\nlocal stats = Quantix.new({\\n    Damage = 25,\\n    Spread = { Base = 1.5, ADS = 0.8 },\\n})\\n-- stats:Get(\\"Spread.Base\\") \u2192 1.5\\n\\n-- Manual registration\\nlocal stats = Quantix.new({})\\nstats:SetBase(\\"Damage\\", 25)\\n```","params":[{"name":"data","desc":"Weapon/entity data table. Pass `{}` to register stats manually.","lua_type":"table"}],"returns":[{"desc":"","lua_type":"StatController"}],"function_type":"static","source":{"line":67,"path":"docs/Quantix.lua"}},{"name":"Get","desc":"Returns the final evaluated value of a stat. Result is cached until the\\nstat is invalidated. Conditional stats are always re-evaluated.\\n\\n```lua\\nprint(stats:Get(\\"Damage\\"))        --\x3e 35\\nprint(stats:Get(\\"Spread.Base\\"))   --\x3e 1.5\\n```","params":[{"name":"statName","desc":"The stat key to evaluate.","lua_type":"string"}],"returns":[{"desc":"The final value, or `nil` if the stat has no base.","lua_type":"any"}],"function_type":"method","source":{"line":164,"path":"docs/Quantix.lua"}},{"name":"GetBase","desc":"Returns the raw base value of a stat before any modifiers are applied.\\n\\n```lua\\nprint(stats:GetBase(\\"Damage\\"))   --\x3e 25\\n```","params":[{"name":"statName","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"any"}],"function_type":"method","source":{"line":179,"path":"docs/Quantix.lua"}},{"name":"GetAll","desc":"Evaluates all registered stats and returns them as a `{ [statName]: value }` table.\\n\\n```lua\\nlocal all = stats:GetAll()\\nprint(all[\\"Damage\\"], all[\\"Range\\"])\\n```","params":[],"returns":[{"desc":"","lua_type":"{ [string]: any }"}],"function_type":"method","source":{"line":194,"path":"docs/Quantix.lua"}},{"name":"GetGroup","desc":"Returns all stats whose keys start with `prefix.`, with the prefix stripped.\\n\\n```lua\\n-- Given stats: Spread.Base = 1.5, Spread.ADS = 0.8\\nlocal spread = stats:GetGroup(\\"Spread\\")\\nprint(spread.Base, spread.ADS)   --\x3e 1.5   0.8\\n```","params":[{"name":"prefix","desc":"The dot-path prefix to filter by.","lua_type":"string"}],"returns":[{"desc":"","lua_type":"{ [string]: any }"}],"function_type":"method","source":{"line":211,"path":"docs/Quantix.lua"}},{"name":"AddModifier","desc":"Adds a modifier to the controller. Returns the modifier\'s auto-generated ID,\\nwhich can be passed to `RemoveModifier` later.\\n\\nRequired fields: `Stat`, `Type`, `Value`.\\n\\n```lua\\nlocal id = stats:AddModifier({\\n    Stat      = \\"Damage\\",\\n    Type      = Quantix.Types.FlatAdd,\\n    Value     = 10,\\n    Source    = Quantix.Sources.Attachment,\\n    SourceId  = attachment.Id,\\n    Priority  = 0,\\n})\\n```","params":[{"name":"modifier","desc":"The modifier to add. `Id` is assigned automatically.","lua_type":"Modifier"}],"returns":[{"desc":"The auto-generated modifier ID.","lua_type":"string"}],"function_type":"method","source":{"line":238,"path":"docs/Quantix.lua"}},{"name":"RemoveModifier","desc":"Removes a modifier by its ID. Returns `true` if the modifier was found and\\nremoved, `false` if it did not exist.\\n\\n```lua\\nlocal removed = stats:RemoveModifier(id)\\n```","params":[{"name":"modifierId","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":254,"path":"docs/Quantix.lua"}},{"name":"RemoveBySource","desc":"Removes all modifiers with the given `Source` (and optionally `SourceId`).\\nRuns inside an implicit `Batch`. Returns the number of modifiers removed.\\n\\n```lua\\n-- Remove all modifiers from any attachment with this ID\\nstats:RemoveBySource(Quantix.Sources.Attachment, attachment.Id)\\n\\n-- Remove all Perk modifiers regardless of SourceId\\nstats:RemoveBySource(Quantix.Sources.Perk)\\n```","params":[{"name":"source","desc":"The source category to match.","lua_type":"string"},{"name":"sourceId","desc":"Optional specific source instance to match.","lua_type":"(string | number)?"}],"returns":[{"desc":"The number of modifiers removed.","lua_type":"number"}],"function_type":"method","source":{"line":275,"path":"docs/Quantix.lua"}},{"name":"ReplaceBySource","desc":"Removes all modifiers matching `source`/`sourceId`, then adds `newModifiers`\\natomically inside a single `Batch`. Returns a list of the new modifier IDs.\\n\\n```lua\\nlocal ids = stats:ReplaceBySource(\\n    Quantix.Sources.Attachment,\\n    old.Id,\\n    newAttachment.Modifiers\\n)\\n```","params":[{"name":"source","desc":"","lua_type":"string"},{"name":"sourceId","desc":"","lua_type":"(string | number)?"},{"name":"newModifiers","desc":"","lua_type":"{ Modifier }"}],"returns":[{"desc":"IDs of the newly added modifiers.","lua_type":"{ string }"}],"function_type":"method","source":{"line":297,"path":"docs/Quantix.lua"}},{"name":"ClearAll","desc":"Removes every active modifier. Runs inside an implicit `Batch`.\\n\\n```lua\\nstats:ClearAll()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":309,"path":"docs/Quantix.lua"}},{"name":"SetBase","desc":"Sets or updates the base value of a stat. Fires `OnStatChanged` if the\\nfinal evaluated value changes.\\n\\n```lua\\nstats:SetBase(\\"Damage\\", 30)\\n```","params":[{"name":"statName","desc":"","lua_type":"string"},{"name":"value","desc":"New base value (number or table).","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":327,"path":"docs/Quantix.lua"}},{"name":"RegisterBehavior","desc":"Registers a base behavior table under a key so that behavior modifiers can\\nbe applied to it via `AddModifier`. Call once during setup.\\n\\n```lua\\nstats:RegisterBehavior(\\"Bullet\\", {\\n    MaxPenetrations = 1,\\n    Gravity         = 9.81,\\n})\\n```","params":[{"name":"behaviorKey","desc":"Unique key for this behavior, used as the `Stat` field in modifiers.","lua_type":"string"},{"name":"baseBehavior","desc":"The unmodified base behavior definition.","lua_type":"table"}],"returns":[],"function_type":"method","source":{"line":346,"path":"docs/Quantix.lua"}},{"name":"Evaluate","desc":"Evaluates behavior modifiers for `behaviorKey` and returns the merged\\nbehavior table and collected hooks.\\n\\n```lua\\nlocal behavior, hooks = stats:Evaluate(\\"Bullet\\", baseBehavior)\\n-- behavior: merged table (no _Hooks key)\\n-- hooks: { [eventName] = { fn, fn, ... } }\\n\\nfor _, fn in hooks.OnPierce or {} do\\n    fn(ctx, result, velocity)\\nend\\n```","params":[{"name":"behaviorKey","desc":"The behavior key (must be registered via `RegisterBehavior`).","lua_type":"string"},{"name":"baseBehavior","desc":"Fallback if no modifiers have been applied yet.","lua_type":"table"}],"returns":[{"desc":"The final merged behavior table.","lua_type":"table"},{"desc":"Hooks table: `{ [eventName] = { fn, ... } }`.","lua_type":"table"}],"function_type":"method","source":{"line":372,"path":"docs/Quantix.lua"}},{"name":"Batch","desc":"Runs `fn` inside a batch. All `OnStatChanged`, `OnModifierAdded`, and\\n`OnModifierRemoved` signals are deferred until `fn` returns, then fired\\nonce per changed stat. `OnBatchEnd` fires last.\\n\\n```lua\\nstats:Batch(function()\\n    stats:RemoveBySource(Quantix.Sources.Attachment, id)\\n    stats:AddModifier({ Stat = \\"Damage\\", Type = \\"FlatAdd\\",  Value = 8,   Source = \\"Attachment\\", SourceId = id })\\n    stats:AddModifier({ Stat = \\"Range\\",  Type = \\"Multiply\\", Value = 0.1, Source = \\"Attachment\\", SourceId = id })\\nend)\\n```","params":[],"returns":[],"function_type":"method","source":{"line":392,"path":"docs/Quantix.lua"}},{"name":"BeginBatch","desc":"Manually begins a batch. Prefer `Batch` for automatic error handling.\\n\\n```lua\\nstats:BeginBatch()\\n-- ... modifier changes ...\\nstats:EndBatch()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":406,"path":"docs/Quantix.lua"}},{"name":"EndBatch","desc":"Ends the active batch, flushing deferred signals.","params":[],"returns":[],"function_type":"method","source":{"line":414,"path":"docs/Quantix.lua"}},{"name":"GetModifiersForStat","desc":"Returns all active modifiers registered for `statName`.\\n\\n```lua\\nfor _, mod in stats:GetModifiersForStat(\\"Damage\\") do\\n    print(mod.Id, mod.Type, mod.Value)\\nend\\n```","params":[{"name":"statName","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"{ Modifier }"}],"function_type":"method","source":{"line":433,"path":"docs/Quantix.lua"}},{"name":"GetModifiers","desc":"Returns all active modifiers across all stats.","params":[],"returns":[{"desc":"","lua_type":"{ Modifier }"}],"function_type":"method","source":{"line":443,"path":"docs/Quantix.lua"}},{"name":"GetModifierById","desc":"Returns the modifier with the given ID, or `nil` if it does not exist.","params":[{"name":"modifierId","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Modifier?"}],"function_type":"method","source":{"line":454,"path":"docs/Quantix.lua"}},{"name":"Trace","desc":"Returns a formatted multi-line string showing the full evaluation pipeline\\nfor `statName`: base value, all active modifiers, per-phase accumulators,\\nand final result. Skipped (condition-failed) modifiers are listed separately.\\n\\n```lua\\nprint(stats:Trace(\\"Damage\\"))\\n-- Stat:  Damage\\n-- Base:  25\\n-- Active modifiers: 2\\n--   [FlatAdd] Attachment/  value=10  priority=0\\n-- Phase [FlatAdd]:\\n--   FlatAdd: { sum=10 }\\n-- = Final: 35\\n```","params":[{"name":"statName","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"string"}],"function_type":"method","source":{"line":480,"path":"docs/Quantix.lua"}},{"name":"DebugDump","desc":"Prints a full dump of all registered stats and active modifiers to the\\nRoblox console. Useful for in-editor inspection.\\n\\n```lua\\nstats:DebugDump()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":493,"path":"docs/Quantix.lua"}},{"name":"Destroy","desc":"Destroys the controller. Disconnects all signals and clears all internal\\nstate. Always call this when the owning entity (weapon, character) is removed.\\n\\n```lua\\nstats:Destroy()\\n```","params":[],"returns":[],"function_type":"method","source":{"line":508,"path":"docs/Quantix.lua"}}],"properties":[{"name":"Types","desc":"Table of all registered modifier type name constants.\\n\\n| Key | Value |\\n|-----|-------|\\n| `SetBase` | `\\"SetBase\\"` |\\n| `FlatAdd` | `\\"FlatAdd\\"` |\\n| `AddPercent` | `\\"AddPercent\\"` |\\n| `Multiply` | `\\"Multiply\\"` |\\n| `Override` | `\\"Override\\"` |\\n| `MinOverride` | `\\"MinOverride\\"` |\\n| `MaxOverride` | `\\"MaxOverride\\"` |\\n| `ClampMin` | `\\"ClampMin\\"` |\\n| `ClampMax` | `\\"ClampMax\\"` |\\n| `StackUnique` | `\\"StackUnique\\"` |\\n| `Lock` | `\\"Lock\\"` |\\n| `BehaviorReplace` | `\\"BehaviorReplace\\"` |\\n| `BehaviorOverride` | `\\"BehaviorOverride\\"` |\\n| `BehaviorDeepMerge` | `\\"BehaviorDeepMerge\\"` |\\n| `BehaviorHook` | `\\"BehaviorHook\\"` |\\n| `BehaviorExclusive` | `\\"BehaviorExclusive\\"` |\\n\\n```lua\\nstats:AddModifier({ ..., Type = Quantix.Types.FlatAdd })\\n```","lua_type":"{ [string]: string }","source":{"line":100,"path":"docs/Quantix.lua"}},{"name":"Sources","desc":"Built-in source category constants for tagging modifiers.\\n\\n| Key | Value |\\n|-----|-------|\\n| `Attachment` | `\\"Attachment\\"` |\\n| `Ammo` | `\\"Ammo\\"` |\\n| `Perk` | `\\"Perk\\"` |\\n| `State` | `\\"State\\"` |\\n| `System` | `\\"System\\"` |\\n| `Ballistics` | `\\"Ballistics\\"` |\\n\\n```lua\\nstats:AddModifier({ ..., Source = Quantix.Sources.Attachment, SourceId = id })\\nstats:RemoveBySource(Quantix.Sources.Attachment, id)\\n```","lua_type":"{ [string]: string }","source":{"line":122,"path":"docs/Quantix.lua"}},{"name":"Signals","desc":"Lifecycle signals for this controller.\\n\\n| Signal | Parameters | Fires when |\\n|--------|-----------|------------|\\n| `OnStatChanged` | `statName: string, newValue: any, oldValue: any` | A stat\'s final value changed |\\n| `OnModifierAdded` | `modifier: Modifier` | A modifier was added |\\n| `OnModifierRemoved` | `modifierId: string` | A modifier was removed |\\n| `OnBatchEnd` | (none) | A `Batch` completed |\\n\\n```lua\\nstats.Signals.OnStatChanged:Connect(function(statName, newValue, oldValue)\\n    print(statName, oldValue, \\"\u2192\\", newValue)\\nend)\\n```","lua_type":"StatControllerSignals","source":{"line":145,"path":"docs/Quantix.lua"}}],"types":[],"name":"Quantix","desc":"Deterministic, phase-ordered stat modifier system for Roblox Luau.\\n\\nQuantix manages numeric and table-based stats through a typed modifier\\npipeline. Modifiers are sorted into phases\\n(`SetBase \u2192 FlatAdd \u2192 AddPercent \u2192 Multiply \u2192 Override \u2192 Clamp \u2192 Lock`),\\nevaluated in a fixed order, and cached until invalidated.\\n\\nBehavior modifier types (`BehaviorOverride`, `BehaviorDeepMerge`,\\n`BehaviorHook`, `BehaviorExclusive`, `BehaviorReplace`) run through the\\nsame pipeline, replacing ad-hoc merge logic for table-based stats.\\n\\n```lua\\nlocal Quantix = require(ReplicatedStorage.Quantix)\\n\\nlocal stats = Quantix.new({\\n    Damage  = 25,\\n    Range   = 50,\\n    Spread  = { Base = 1.5, ADS = 0.8 },\\n})\\n\\nlocal id = stats:AddModifier({\\n    Stat   = \\"Damage\\",\\n    Type   = Quantix.Types.FlatAdd,\\n    Value  = 10,\\n    Source = Quantix.Sources.Attachment,\\n})\\n\\nprint(stats:Get(\\"Damage\\"))   --\x3e 35\\nstats:RemoveModifier(id)\\nprint(stats:Get(\\"Damage\\"))   --\x3e 25\\n```","source":{"line":40,"path":"docs/Quantix.lua"}}')}}]);